// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MAXN 100005
int grid[MAXN][MAXN];
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            grid[i][j] = -1; // no color
        }
    }
    for (int i = 0; i < M; i++) {
        int type, idx, color;
        scanf("%d %d %d", &type, &idx, &color);
        if (type == 1) { // row
            for (int j = 0; j < N; j++) {
                if (grid[idx - 1][j] == -1) {
                    grid[idx - 1][j] = color;
                } else if (grid[idx - 1][j] != color) {
                    grid[idx - 1][j] = 2; // yellow
                }
            }
        } else if (type == 2) { // column
            for (int j = 0; j < N; j++) {
                if (grid[j][idx - 1] == -1) {
                    grid[j][idx - 1] = color;
                } else if (grid[j][idx - 1] != color) {
                    grid[j][idx - 1] = 2; // yellow
                }
            }
        } else { // diagonal
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    if (j + k + 1 == idx) {
                        if (grid[j][k] == -1) {
                            grid[j][k] = color;
                        } else if (grid[j][k] != color) {
                            grid[j][k] = 2; // yellow
                        }
                    }
                }
            }
        }
    }
    int noColor = 0, red = 0, green = 0, yellow = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (grid[i][j] == -1) {
                noColor++;
            } else if (grid[i][j] == 0) {
                green++;
            } else if (grid[i][j] == 1) {
                red++;
            } else {
                yellow++;
            }
        }
    }
    printf("%d %d %d %d\n", noColor, red, green, yellow);
    return 0;
}

