                grid[idx - 1][j] = 2; // yellow
            }
        }
    } else if (type === 2) { // column
        for (let j = 0; j < N; j++) {
            if (grid[j][idx - 1] === -1) {
                grid[j][idx - 1] = color;
            } else if (grid[j][idx - 1] !== color) {
                grid[j][idx - 1] = 2; // yellow
            }
        }
    } else { // diagonal
        for (let j = 0; j < N; j++) {
            for (let k = 0; k < N; k++) {
                if (j + k + 1 === idx) {
                    if (grid[j][k] === -1) {
                        grid[j][k] = color;
